1	use pcode_model::{Instruction, Opcode, Operand, Program, WORD};
2	use std::collections::HashSet;
3	use std::fmt::Write;
4	
5	/// Errors during assembly emission.
6	#[derive(Debug)]
7	pub enum EmitError {
8	    /// A fmt::Write call failed.
9	    Fmt(std::fmt::Error),
10	    /// Global variable offset too large for single-instruction access.
11	    GlobalOffsetTooLarge { addr: u32 },
12	    /// Local variable offset too large for single-instruction access.
13	    LocalOffsetTooLarge { offset: u8 },
14	}
15	
16	impl std::fmt::Display for EmitError {
17	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
18	        match self {
19	            EmitError::Fmt(e) => write!(f, "format error: {e}"),
20	            EmitError::GlobalOffsetTooLarge { addr } => {
21	                write!(f, "global offset too large: {addr} (max 42)")
22	            }
23	            EmitError::LocalOffsetTooLarge { offset } => {
24	                write!(f, "local offset too large: {offset} (max 41)")
25	            }
26	        }
27	    }
28	}
29	
30	impl std::error::Error for EmitError {}
31	
32	impl From<std::fmt::Error> for EmitError {
33	    fn from(e: std::fmt::Error) -> Self {
34	        EmitError::Fmt(e)
35	    }
36	}
37	
38	/// Initial stack pointer address. Programs start with sp set here;
39	/// the stack grows downward from this address.
40	const STACK_TOP: u32 = 0x2000;
41	
42	/// Emit COR24 assembly for a decoded p-code program.
43	///
44	/// Returns the complete assembly text as a string, ready to be written
45	/// to a `.s` file and assembled by the COR24 cross-assembler (as24).
46	pub fn emit_program(program: &Program, source_name: &str) -> Result<String, EmitError> {
47	    let mut e = Emitter::new(program);
48	    e.prologue(program, source_name)?;
49	    for instr in &program.instructions {
50	        e.instruction(instr)?;
51	    }
52	    e.epilogue(program)?;
53	    Ok(e.out)
54	}
55	
56	// ── Emitter ────────────────────────────────────────────────────────
57	
58	struct Emitter {
59	    out: String,
60	    /// P-code PCs that are jump/branch targets and need labels.
61	    targets: HashSet<u32>,
62	    /// Counter for generating unique skip labels (for conditional branches).
63	    skip_id: u32,
64	}
65	
66	impl Emitter {
67	    fn new(program: &Program) -> Self {
68	        Self {
69	            out: String::with_capacity(8192),
70	            targets: collect_branch_targets(&program.instructions),
71	            skip_id: 0,
72	        }
73	    }
74	
75	    fn next_skip(&mut self) -> u32 {
76	        let id = self.skip_id;
77	        self.skip_id += 1;
78	        id
79	    }
80	
81	    // ── Prologue / epilogue ────────────────────────────────────────
82	
83	    fn prologue(&mut self, program: &Program, source_name: &str) -> Result<(), EmitError> {
84	        writeln!(self.out, "; Generated by pc-aotc from {source_name}")?;
85	        writeln!(self.out, "; COR24 p-code AOT compiler output")?;
86	        writeln!(self.out)?;
87	        writeln!(self.out, "    la      sp, {STACK_TOP}")?;
88	        if program.entry_point != 0 {
89	            writeln!(self.out, "    la      r2, .L{:04X}", program.entry_point)?;
90	            writeln!(self.out, "    jmp     (r2)")?;
91	        }
92	        writeln!(self.out)?;
93	        Ok(())
94	    }
95	
96	    fn epilogue(&mut self, program: &Program) -> Result<(), EmitError> {
97	        // Halt loop (target for halt opcode)
98	        writeln!(self.out, "_p24_halt:")?;
99	        writeln!(self.out, "    bra     _p24_halt")?;
100	        writeln!(self.out)?;
101	
102	        // Global variable storage
103	        if program.global_count > 0 {
104	            let size = program.global_count as usize * WORD;
105	            writeln!(
106	                self.out,
107	                "; Global variables ({} words)",
108	                program.global_count
109	            )?;
110	            writeln!(self.out, "_p24_globals:")?;
111	            // Emit zero-initialized bytes
112	            for _ in 0..size {
113	                writeln!(self.out, "    .byte   0")?;
114	            }
115	            writeln!(self.out)?;
116	        }
117	
118	        // Data segment (if any)
119	        if !program.data.is_empty() {
120	            writeln!(self.out, "; Data segment ({} bytes)", program.data.len())?;
121	            writeln!(self.out, "_p24_data:")?;
122	            for chunk in program.data.chunks(16) {
123	                let bytes: Vec<String> = chunk.iter().map(|b| format!("{b}")).collect();
124	                writeln!(self.out, "    .byte   {}", bytes.join(","))?;
125	            }
126	            writeln!(self.out)?;
127	        }
128	
129	        Ok(())
130	    }
131	
132	    // ── Instruction dispatch ───────────────────────────────────────
133	
134	    fn instruction(&mut self, instr: &Instruction) -> Result<(), EmitError> {
135	        // Emit label if this PC is a branch target or procedure entry
136	        if self.targets.contains(&instr.pc) {
137	            writeln!(self.out, ".L{:04X}:", instr.pc)?;
138	        }
139	
140	        // Comment with p-code disassembly
141	        self.pcode_comment(instr)?;
142	
143	        match instr.op {
144	            // Stack operations
145	            Opcode::Halt => self.op_halt()?,
146	            Opcode::Push => self.op_push(instr)?,
147	            Opcode::PushS => self.op_push_s(instr)?,
148	            Opcode::Dup => self.op_dup()?,
149	            Opcode::Drop => self.op_drop()?,
150	            Opcode::Swap => self.op_swap()?,
151	            Opcode::Over => self.op_over()?,
152	
153	            // Arithmetic
154	            Opcode::Add => self.op_commutative_binop("add")?,
155	            Opcode::Sub => self.op_sub()?,
156	            Opcode::Mul => self.op_commutative_binop("mul")?,
157	            Opcode::Neg => self.op_neg()?,
158	
159	            // Comparisons
160	            Opcode::Eq => self.op_eq()?,
161	            Opcode::Ne => self.op_ne()?,
162	            Opcode::Lt => self.op_lt()?,
163	            Opcode::Le => self.op_le()?,
164	            Opcode::Gt => self.op_gt()?,
165	            Opcode::Ge => self.op_ge()?,
166	
167	            // Control flow
168	            Opcode::Jmp => self.op_jmp(instr)?,
169	            Opcode::Jz => self.op_jz(instr)?,
170	            Opcode::Jnz => self.op_jnz(instr)?,
171	
172	            // Frame / variable access
173	            Opcode::Enter => self.op_enter(instr)?,
174	            Opcode::Leave => self.op_leave()?,
175	            Opcode::Loadl => self.op_loadl(instr)?,
176	            Opcode::Storel => self.op_storel(instr)?,
177	            Opcode::Loadg => self.op_loadg(instr)?,
178	            Opcode::Storeg => self.op_storeg(instr)?,
179	
180	            // Unsupported — emit a comment so the file is still parseable
181	            _ => {
182	                writeln!(self.out, "    ; TODO: unsupported opcode {}", instr.op)?;
183	            }
184	        }
185	        writeln!(self.out)?;
186	        Ok(())
187	    }
188	
189	    // ── Stack operations ───────────────────────────────────────────
190	
191	    fn op_halt(&mut self) -> Result<(), EmitError> {
192	        writeln!(self.out, "    la      r2, _p24_halt")?;
193	        writeln!(self.out, "    jmp     (r2)")?;
194	        Ok(())
195	    }
196	
197	    fn op_push(&mut self, instr: &Instruction) -> Result<(), EmitError> {
198	        if let Operand::Imm24(val) = instr.operand {
199	            let sval = sign_extend_24(val);
200	            self.load_immediate("r0", sval)?;
201	            writeln!(self.out, "    push    r0")?;
202	        }
203	        Ok(())
204	    }
205	
206	    fn op_push_s(&mut self, instr: &Instruction) -> Result<(), EmitError> {
207	        if let Operand::Imm8(val) = instr.operand {
208	            let sval = val as i8 as i32;
209	            self.load_immediate("r0", sval)?;
210	            writeln!(self.out, "    push    r0")?;
211	        }
212	        Ok(())
213	    }
214	
215	    fn op_dup(&mut self) -> Result<(), EmitError> {
216	        writeln!(self.out, "    lw      r0, 0(sp)")?;
217	        writeln!(self.out, "    push    r0")?;
218	        Ok(())
219	    }
220	
221	    fn op_drop(&mut self) -> Result<(), EmitError> {
222	        writeln!(self.out, "    pop     r0")?;
223	        Ok(())
224	    }
225	
226	    fn op_swap(&mut self) -> Result<(), EmitError> {
227	        writeln!(self.out, "    pop     r0")?;
228	        writeln!(self.out, "    pop     r1")?;
229	        writeln!(self.out, "    push    r0")?;
230	        writeln!(self.out, "    push    r1")?;
231	        Ok(())
232	    }
233	
234	    fn op_over(&mut self) -> Result<(), EmitError> {
235	        // NOS is one word below TOS: sp+3
236	        writeln!(self.out, "    lw      r0, 3(sp)")?;
237	        writeln!(self.out, "    push    r0")?;
238	        Ok(())
239	    }
240	
241	    // ── Arithmetic ─────────────────────────────────────────────────
242	
243	    /// Emit a commutative binary op (add, mul): pop two, compute, push result.
244	    fn op_commutative_binop(&mut self, mnemonic: &str) -> Result<(), EmitError> {
245	        writeln!(self.out, "    pop     r0")?; // TOS
246	        writeln!(self.out, "    pop     r1")?; // NOS
247	        writeln!(self.out, "    {mnemonic:<8}r0, r1")?;
248	        writeln!(self.out, "    push    r0")?;
249	        Ok(())
250	    }
251	
252	    /// Sub: NOS - TOS. Non-commutative, so operand order matters.
253	    fn op_sub(&mut self) -> Result<(), EmitError> {
254	        writeln!(self.out, "    pop     r0")?; // TOS
255	        writeln!(self.out, "    pop     r1")?; // NOS
256	        writeln!(self.out, "    sub     r1, r0")?; // r1 = NOS - TOS
257	        writeln!(self.out, "    push    r1")?;
258	        Ok(())
259	    }
260	
261	    /// Neg: -TOS. COR24 has no neg instruction, so compute 0 - TOS.
262	    fn op_neg(&mut self) -> Result<(), EmitError> {
263	        writeln!(self.out, "    pop     r1")?; // TOS
264	        writeln!(self.out, "    mov     r0, z")?; // r0 = 0
265	        writeln!(self.out, "    sub     r0, r1")?; // r0 = 0 - TOS
266	        writeln!(self.out, "    push    r0")?;
267	        Ok(())
268	    }
269	
270	    // ── Comparisons ────────────────────────────────────────────────
271	    //
272	    // COR24 has: ceq (==), cls (signed <), clu (unsigned <).
273	    // The condition flag C is read via `mov rX, c`.
274	    // For ne/le/ge we compute the inverse by checking if C == 0.
275	
276	    /// Eq: NOS == TOS → 1, else 0.
277	    fn op_eq(&mut self) -> Result<(), EmitError> {
278	        writeln!(self.out, "    pop     r0")?; // TOS
279	        writeln!(self.out, "    pop     r1")?; // NOS
280	        writeln!(self.out, "    ceq     r1, r0")?;
281	        writeln!(self.out, "    mov     r0, c")?;
282	        writeln!(self.out, "    push    r0")?;
283	        Ok(())
284	    }
285	
286	    /// Ne: NOS != TOS → 1, else 0. Invert eq result.
287	    fn op_ne(&mut self) -> Result<(), EmitError> {
288	        writeln!(self.out, "    pop     r0")?;
289	        writeln!(self.out, "    pop     r1")?;
290	        writeln!(self.out, "    ceq     r1, r0")?; // C = (NOS == TOS)
291	        writeln!(self.out, "    mov     r0, c")?; // r0 = eq result
292	        writeln!(self.out, "    ceq     r0, z")?; // C = (r0 == 0) = not-equal
293	        writeln!(self.out, "    mov     r0, c")?;
294	        writeln!(self.out, "    push    r0")?;
295	        Ok(())
296	    }
297	
298	    /// Lt: NOS < TOS (signed) → 1, else 0.
299	    fn op_lt(&mut self) -> Result<(), EmitError> {
300	        writeln!(self.out, "    pop     r0")?; // TOS
301	        writeln!(self.out, "    pop     r1")?; // NOS
302	        writeln!(self.out, "    cls     r1, r0")?; // C = (NOS < TOS)
303	        writeln!(self.out, "    mov     r0, c")?;
304	        writeln!(self.out, "    push    r0")?;
305	        Ok(())
306	    }
307	
308	    /// Le: NOS <= TOS ⟺ ¬(TOS < NOS).
309	    fn op_le(&mut self) -> Result<(), EmitError> {
310	        writeln!(self.out, "    pop     r0")?; // TOS
311	        writeln!(self.out, "    pop     r1")?; // NOS
312	        writeln!(self.out, "    cls     r0, r1")?; // C = (TOS < NOS)
313	        writeln!(self.out, "    mov     r0, c")?; // r0 = (TOS < NOS)
314	        writeln!(self.out, "    ceq     r0, z")?; // C = ¬(TOS < NOS) = (NOS <= TOS)
315	        writeln!(self.out, "    mov     r0, c")?;
316	        writeln!(self.out, "    push    r0")?;
317	        Ok(())
318	    }
319	
320	    /// Gt: NOS > TOS ⟺ TOS < NOS.
321	    fn op_gt(&mut self) -> Result<(), EmitError> {
322	        writeln!(self.out, "    pop     r0")?; // TOS
323	        writeln!(self.out, "    pop     r1")?; // NOS
324	        writeln!(self.out, "    cls     r0, r1")?; // C = (TOS < NOS) = (NOS > TOS)
325	        writeln!(self.out, "    mov     r0, c")?;
326	        writeln!(self.out, "    push    r0")?;
327	        Ok(())
328	    }
329	
330	    /// Ge: NOS >= TOS ⟺ ¬(NOS < TOS).
331	    fn op_ge(&mut self) -> Result<(), EmitError> {
332	        writeln!(self.out, "    pop     r0")?; // TOS
333	        writeln!(self.out, "    pop     r1")?; // NOS
334	        writeln!(self.out, "    cls     r1, r0")?; // C = (NOS < TOS)
335	        writeln!(self.out, "    mov     r0, c")?; // r0 = (NOS < TOS)
336	        writeln!(self.out, "    ceq     r0, z")?; // C = ¬(NOS < TOS) = (NOS >= TOS)
337	        writeln!(self.out, "    mov     r0, c")?;
338	        writeln!(self.out, "    push    r0")?;
339	        Ok(())
340	    }
341	
342	    // ── Control flow ───────────────────────────────────────────────
343	
344	    /// Unconditional jump. Uses absolute addressing via la + jmp.
345	    fn op_jmp(&mut self, instr: &Instruction) -> Result<(), EmitError> {
346	        if let Operand::Imm24(addr) = instr.operand {
347	            writeln!(self.out, "    la      r2, .L{addr:04X}")?;
348	            writeln!(self.out, "    jmp     (r2)")?;
349	        }
350	        Ok(())
351	    }
352	
353	    /// Jump if zero: pop TOS, branch to target if TOS == 0.
354	    fn op_jz(&mut self, instr: &Instruction) -> Result<(), EmitError> {
355	        if let Operand::Imm24(addr) = instr.operand {
356	            let skip = self.next_skip();
357	            writeln!(self.out, "    pop     r0")?;
358	            writeln!(self.out, "    ceq     r0, z")?; // C = (TOS == 0)
359	            writeln!(self.out, "    brf     .Lskip{skip}")?; // skip if not zero
360	            writeln!(self.out, "    la      r2, .L{addr:04X}")?;
361	            writeln!(self.out, "    jmp     (r2)")?;
362	            writeln!(self.out, ".Lskip{skip}:")?;
363	        }
364	        Ok(())
365	    }
366	
367	    /// Jump if non-zero: pop TOS, branch to target if TOS != 0.
368	    fn op_jnz(&mut self, instr: &Instruction) -> Result<(), EmitError> {
369	        if let Operand::Imm24(addr) = instr.operand {
370	            let skip = self.next_skip();
371	            writeln!(self.out, "    pop     r0")?;
372	            writeln!(self.out, "    ceq     r0, z")?; // C = (TOS == 0)
373	            writeln!(self.out, "    brt     .Lskip{skip}")?; // skip if zero
374	            writeln!(self.out, "    la      r2, .L{addr:04X}")?;
375	            writeln!(self.out, "    jmp     (r2)")?;
376	            writeln!(self.out, ".Lskip{skip}:")?;
377	        }
378	        Ok(())
379	    }
380	
381	    // ── Frame / variable access ────────────────────────────────────
382	
383	    /// Enter: set up activation frame, allocate local variable slots.
384	    ///
385	    /// Frame layout (stack grows downward):
386	    /// ```text
387	    ///     [saved fp]    ← fp points here after "mov fp, sp"
388	    ///     [local 0]     ← fp - 3
389	    ///     [local 1]     ← fp - 6
390	    ///     ...
391	    ///     [local N-1]   ← fp - N*3
392	    ///     [eval stack]  ← sp (current top)
393	    /// ```
394	    fn op_enter(&mut self, instr: &Instruction) -> Result<(), EmitError> {
395	        if let Operand::Imm8(nlocals) = instr.operand {
396	            writeln!(self.out, "    push    fp")?;
397	            writeln!(self.out, "    mov     fp, sp")?;
398	            if nlocals > 0 {
399	                let size = nlocals as u32 * WORD as u32;
400	                writeln!(self.out, "    sub     sp, {size}")?;
401	            }
402	        }
403	        Ok(())
404	    }
405	
406	    /// Leave: tear down activation frame (inverse of enter).
407	    fn op_leave(&mut self) -> Result<(), EmitError> {
408	        writeln!(self.out, "    mov     sp, fp")?;
409	        writeln!(self.out, "    pop     fp")?;
410	        Ok(())
411	    }
412	
413	    /// Load local variable at slot offset onto eval stack.
414	    fn op_loadl(&mut self, instr: &Instruction) -> Result<(), EmitError> {
415	        if let Operand::Imm8(slot) = instr.operand {
416	            let offset = local_frame_offset(slot)?;
417	            writeln!(self.out, "    lw      r0, {offset}(fp)")?;
418	            writeln!(self.out, "    push    r0")?;
419	        }
420	        Ok(())
421	    }
422	
423	    /// Store TOS into local variable at slot offset.
424	    fn op_storel(&mut self, instr: &Instruction) -> Result<(), EmitError> {
425	        if let Operand::Imm8(slot) = instr.operand {
426	            let offset = local_frame_offset(slot)?;
427	            writeln!(self.out, "    pop     r0")?;
428	            writeln!(self.out, "    sw      r0, {offset}(fp)")?;
429	        }
430	        Ok(())
431	    }
432	
433	    /// Load global variable onto eval stack.
434	    fn op_loadg(&mut self, instr: &Instruction) -> Result<(), EmitError> {
435	        if let Operand::Imm24(addr) = instr.operand {
436	            let byte_offset = addr as usize * WORD;
437	            writeln!(self.out, "    la      r1, _p24_globals")?;
438	            if byte_offset <= 127 {
439	                writeln!(self.out, "    lw      r0, {byte_offset}(r1)")?;
440	            } else {
441	                writeln!(self.out, "    la      r2, {byte_offset}")?;
442	                writeln!(self.out, "    add     r1, r2")?;
443	                writeln!(self.out, "    lw      r0, 0(r1)")?;
444	            }
445	            writeln!(self.out, "    push    r0")?;
446	        }
447	        Ok(())
448	    }
449	
450	    /// Store TOS into global variable.
451	    fn op_storeg(&mut self, instr: &Instruction) -> Result<(), EmitError> {
452	        if let Operand::Imm24(addr) = instr.operand {
453	            let byte_offset = addr as usize * WORD;
454	            writeln!(self.out, "    pop     r0")?;
455	            writeln!(self.out, "    la      r1, _p24_globals")?;
456	            if byte_offset <= 127 {
457	                writeln!(self.out, "    sw      r0, {byte_offset}(r1)")?;
458	            } else {
459	                writeln!(self.out, "    la      r2, {byte_offset}")?;
460	                writeln!(self.out, "    add     r1, r2")?;
461	                writeln!(self.out, "    sw      r0, 0(r1)")?;
462	            }
463	        }
464	        Ok(())
465	    }
466	
467	    // ── Helpers ────────────────────────────────────────────────────
468	
469	    /// Emit a p-code disassembly comment line.
470	    fn pcode_comment(&mut self, instr: &Instruction) -> Result<(), EmitError> {
471	        writeln!(self.out, "    ; {instr}")?;
472	        Ok(())
473	    }
474	
475	    /// Emit instructions to load an immediate value into a register.
476	    /// Chooses the smallest encoding: lc (8-bit signed), lcu (8-bit unsigned), or la (24-bit).
477	    fn load_immediate(&mut self, reg: &str, val: i32) -> Result<(), EmitError> {
478	        if (-128..=127).contains(&val) {
479	            writeln!(self.out, "    lc      {reg}, {val}")?;
480	        } else if (0..=255).contains(&val) {
481	            writeln!(self.out, "    lcu     {reg}, {val}")?;
482	        } else {
483	            writeln!(self.out, "    la      {reg}, {val}")?;
484	        }
485	        Ok(())
486	    }
487	}
488	
489	// ── Utility functions ──────────────────────────────────────────────
490	
491	/// Compute the frame offset for a local variable slot.
492	/// Local slot N is at fp - (N+1)*3.
493	fn local_frame_offset(slot: u8) -> Result<i8, EmitError> {
494	    let offset = -((slot as i16 + 1) * WORD as i16);
495	    if offset < -128 {
496	        return Err(EmitError::LocalOffsetTooLarge { offset: slot });
497	    }
498	    Ok(offset as i8)
499	}
500	
501	/// Sign-extend a 24-bit value stored in a u32 to an i32.
502	fn sign_extend_24(val: u32) -> i32 {
503	    if val & 0x80_0000 != 0 {
504	        (val | 0xFF00_0000) as i32
505	    } else {
506	        val as i32
507	    }
508	}
509	
510	/// Pre-scan instructions to find all PCs that are branch/jump targets.
511	fn collect_branch_targets(instructions: &[Instruction]) -> HashSet<u32> {
512	    let mut targets = HashSet::new();
513	    for instr in instructions {
514	        match instr.op {
515	            Opcode::Jmp | Opcode::Jz | Opcode::Jnz | Opcode::Call | Opcode::Calln => {
516	                match instr.operand {
517	                    Operand::Imm24(addr) => {
518	                        targets.insert(addr);
519	                    }
520	                    Operand::D8A24 { addr, .. } => {
521	                        targets.insert(addr);
522	                    }
523	                    _ => {}
524	                }
525	            }
526	            _ => {}
527	        }
528	    }
529	    // Also mark procedure entry points
530	    for instr in instructions {
531	        if instr.op == Opcode::Enter {
532	            targets.insert(instr.pc);
533	        }
534	    }
535	    targets
536	}
