1	//! P-code binary file decoder.
2	//!
3	//! Reads a `.p24` binary (header + code + data) and produces a [`Program`]
4	//! with fully decoded instructions and procedure metadata.
5	
6	use crate::{
7	    Encoding, Instruction, Opcode, Operand, ProcedureInfo, Program, P24_HEADER_SIZE, P24_MAGIC,
8	    P24_VERSION,
9	};
10	
11	/// Errors that can occur while decoding a `.p24` binary.
12	#[derive(Debug, Clone, PartialEq, Eq)]
13	pub enum DecodeError {
14	    /// File is too short to contain a valid header.
15	    TooShort,
16	    /// Magic bytes don't match "P24\0".
17	    BadMagic,
18	    /// Unsupported version byte.
19	    BadVersion(u8),
20	    /// Body is shorter than declared code_size + data_size.
21	    Truncated,
22	    /// Invalid opcode byte encountered during instruction decoding.
23	    InvalidOpcode { pc: u32, byte: u8 },
24	    /// Instruction operand extends past end of code segment.
25	    UnexpectedEnd { pc: u32 },
26	}
27	
28	impl std::fmt::Display for DecodeError {
29	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
30	        match self {
31	            DecodeError::TooShort => write!(f, "file too short for .p24 header"),
32	            DecodeError::BadMagic => write!(f, "invalid .p24 magic bytes"),
33	            DecodeError::BadVersion(v) => write!(f, "unsupported .p24 version: {v}"),
34	            DecodeError::Truncated => write!(f, "file body truncated"),
35	            DecodeError::InvalidOpcode { pc, byte } => {
36	                write!(f, "invalid opcode 0x{byte:02X} at PC=0x{pc:04X}")
37	            }
38	            DecodeError::UnexpectedEnd { pc } => {
39	                write!(f, "instruction at PC=0x{pc:04X} extends past end of code")
40	            }
41	        }
42	    }
43	}
44	
45	impl std::error::Error for DecodeError {}
46	
47	fn read_le24(bytes: &[u8]) -> u32 {
48	    bytes[0] as u32 | ((bytes[1] as u32) << 8) | ((bytes[2] as u32) << 16)
49	}
50	
51	/// Decode a `.p24` binary into a [`Program`].
52	pub fn decode_program(binary: &[u8]) -> Result<Program, DecodeError> {
53	    // ── Parse header ────────────────────────────────────────────────
54	    if binary.len() < P24_HEADER_SIZE {
55	        return Err(DecodeError::TooShort);
56	    }
57	    if binary[0..4] != P24_MAGIC {
58	        return Err(DecodeError::BadMagic);
59	    }
60	    let version = binary[4];
61	    if version != P24_VERSION {
62	        return Err(DecodeError::BadVersion(version));
63	    }
64	
65	    let entry_point = read_le24(&binary[5..8]);
66	    let code_size = read_le24(&binary[8..11]) as usize;
67	    let data_size = read_le24(&binary[11..14]) as usize;
68	    let global_count = read_le24(&binary[14..17]);
69	    // binary[17] is flags, reserved
70	
71	    let body = &binary[P24_HEADER_SIZE..];
72	    if body.len() < code_size + data_size {
73	        return Err(DecodeError::Truncated);
74	    }
75	
76	    let code = &body[..code_size];
77	    let data = body[code_size..code_size + data_size].to_vec();
78	
79	    // ── Decode instructions ─────────────────────────────────────────
80	    let instructions = decode_instructions(code)?;
81	
82	    // ── Extract procedure metadata ──────────────────────────────────
83	    let procedures = extract_procedures(&instructions);
84	
85	    Ok(Program {
86	        entry_point,
87	        instructions,
88	        data,
89	        global_count,
90	        procedures,
91	    })
92	}
93	
94	/// Decode all instructions from a code segment.
95	fn decode_instructions(code: &[u8]) -> Result<Vec<Instruction>, DecodeError> {
96	    let mut instructions = Vec::new();
97	    let mut pc: usize = 0;
98	
99	    while pc < code.len() {
100	        let op_byte = code[pc];
101	        let op = Opcode::from_byte(op_byte).ok_or(DecodeError::InvalidOpcode {
102	            pc: pc as u32,
103	            byte: op_byte,
104	        })?;
105	
106	        let instr_size = op.size();
107	        if pc + instr_size > code.len() {
108	            return Err(DecodeError::UnexpectedEnd { pc: pc as u32 });
109	        }
110	
111	        let operand = match op.encoding() {
112	            Encoding::None => Operand::None,
113	            Encoding::Imm8 => Operand::Imm8(code[pc + 1]),
114	            Encoding::Imm24 => Operand::Imm24(read_le24(&code[pc + 1..pc + 4])),
115	            Encoding::D8A24 => Operand::D8A24 {
116	                depth: code[pc + 1],
117	                addr: read_le24(&code[pc + 2..pc + 5]),
118	            },
119	            Encoding::D8O8 => Operand::D8O8 {
120	                depth: code[pc + 1],
121	                offset: code[pc + 2],
122	            },
123	        };
124	
125	        instructions.push(Instruction {
126	            pc: pc as u32,
127	            op,
128	            operand,
129	        });
130	
131	        pc += instr_size;
132	    }
133	
134	    Ok(instructions)
135	}
136	
137	/// Scan the instruction stream for `enter` instructions to identify procedures.
138	///
139	/// Each procedure starts at the instruction that is the target of a `call`/`calln`,
140	/// but since we don't resolve call targets here, we use `enter` as the marker.
141	/// The procedure's `entry_pc` is set to the PC of the `enter` instruction.
142	/// The procedure extends until the next `enter` or end of instructions.
143	fn extract_procedures(instructions: &[Instruction]) -> Vec<ProcedureInfo> {
144	    let mut procedures = Vec::new();
145	
146	    for (idx, instr) in instructions.iter().enumerate() {
147	        if instr.op == Opcode::Enter {
148	            let num_locals = match instr.operand {
149	                Operand::Imm8(n) => n,
150	                _ => 0,
151	            };
152	
153	            // Close previous procedure if any
154	            if let Some(prev) = procedures.last_mut() {
155	                let prev: &mut ProcedureInfo = prev;
156	                if prev.instr_end == 0 {
157	                    prev.instr_end = idx;
158	                }
159	            }
160	
161	            procedures.push(ProcedureInfo {
162	                entry_pc: instr.pc,
163	                num_locals,
164	                instr_start: idx,
165	                instr_end: 0, // will be filled in
166	            });
167	        }
168	    }
169	
170	    // Close last procedure
171	    if let Some(last) = procedures.last_mut() {
172	        if last.instr_end == 0 {
173	            last.instr_end = instructions.len();
174	        }
175	    }
176	
177	    procedures
178	}
