185	    /// Build a minimal .p24 binary for testing.
186	    fn make_p24(entry: u32, code: &[u8], data: &[u8], globals: u32) -> Vec<u8> {
187	        let mut binary = Vec::with_capacity(P24_HEADER_SIZE + code.len() + data.len());
188	        binary.extend_from_slice(&P24_MAGIC);
